(window.webpackJsonp=window.webpackJsonp||[]).push([[44],{671:function(n,r){n.exports="\x3c!-- \r\ntitle: 02-Linux基础命令\r\nsort: \r\n--\x3e \r\n\r\n# Linux命令\r\n\r\n> 命令有多种类型\r\n\r\n## 帮助\r\n\r\n- type———显示命令类型\r\n\r\n- which——显示可执行程序的位置\r\n\r\n- help———得到内建函数的帮助文档\r\n\r\n  > `--help`显示用法信息\r\n\r\n- apropos——模糊命令搜索\r\n\r\n- man———显示程序手册\r\n\r\n- whatis——简洁的命令说明\r\n\r\n- alias———创建别名\r\n\r\n## 重定向\r\n\r\n> `> clean.txt`：清空文件\r\n>\r\n> `&> output.txt`：标准错误重定向\r\n>\r\n> `2> /dev/null`：错误信息放到垃圾桶\r\n\r\n- cat———连接文件\r\n\r\n  > `cat > out.txt`\r\n  >\r\n  > `Some Text <Ctrl+D>`\r\n\r\n- | ————管道\r\n\r\n  > 将一个命令的输入作为下一个命令的输出\r\n  >\r\n  > `ll xx | less`\r\n\r\n- sort\r\n\r\n  > `ls /bin /usr/bin | sort | less`\r\n\r\n- wc———行数 单词数 字节数\r\n\r\n  > -c\tbyte\r\n  >\r\n  > -m\tcharacter\r\n  >\r\n  > -l\tlines\r\n  >\r\n  > -w\twords\r\n  >\r\n  > -L\tMAX_LEN\r\n\r\n- grep———打印匹配行\r\n\r\n  > -i\tignore\r\n  >\r\n  > -v\t打印不匹配的行\r\n\r\n- head、tail—打印开头、结尾\r\n\r\n  > -n\t行数\r\n  >\r\n  > tail -f 实时预览\r\n\r\n- tee———中转\r\n\r\n  > 输出到文件并沿着管道向下\r\n  >\r\n  > `ll /usr/bin | tee ls.txt | grep zip`\r\n\r\n## Shell\r\n\r\n- `echo 1+1=$((1+1))`\r\n\r\n  > 算数表达式展开\r\n  \r\n- `echo Number_{0..9}{Z..A}`\r\n\r\n  > 花括号展开\r\n\r\n- `echo $(ls)`\r\n\r\n  > 将命令的输出展开为输入使用\r\n  >\r\n  > `ls -l $(which docker)`\r\n\r\n- `echo $HOME`\r\n\r\n  > 显示名为HOME的常量\r\n  >\r\n  > `set | less`：显示所有已定义的常量\r\n\r\n- 符号\r\n\r\n  > `\"\"`：特殊字符失去含义，除去`/$''`\r\n  >\r\n  > `''`：全部特殊字符失去含义\r\n  >\r\n  > `echo \"SomeText $(pwd) $((1+1))\"`：$会展开\r\n  >\r\n  > `echo 'SomeText $(pwd) $((1+1))'`：输出字符串\r\n  >\r\n  > `\\`：使用转义符阻止展开"}}]);